{
  "name": "VitalQuest",
  "description": "An evidence-based, gamified wellness assistant powered by Gemini. Track health metrics, receive safe, food-first nutrition guidance, and level up your health habits."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Gender {
  Male = 'Male',
  Female = 'Female',
  PreferNotToSay = 'PreferNotToSay'
}

export enum ActivityLevel {
  Sedentary = 'Sedentary (office job, little exercise)',
  Light = 'Lightly Active (1-3 days/week)',
  Moderate = 'Moderately Active (3-5 days/week)',
  VeryActive = 'Very Active (6-7 days/week)',
  ExtraActive = 'Extra Active (physical job or training)'
}

export enum Goal {
  FatLoss = 'Fat Loss',
  MuscleGain = 'Muscle Gain',
  Endurance = 'Endurance / Performance',
  GeneralHealth = 'General Health & Maintenance'
}

export enum DietaryRestriction {
  Vegan = 'Vegan',
  Vegetarian = 'Vegetarian',
  GlutenFree = 'Gluten-Free',
  LactoseFree = 'Lactose-Free',
  Kosher = 'Kosher',
  Halal = 'Halal',
  None = 'None'
}

export interface UserProfile {
  age: number;
  gender: Gender;
  heightCm: number;
  weightKg: number;
  activityLevel: ActivityLevel;
  goal: Goal;
  dietaryRestrictions: DietaryRestriction[];
  medicationsOrConditions: string;
  sleepHours: number;
}

// Calculated locally
export interface CalculatedMetrics {
  bmi: number;
  bmr: number;
  tdee: number;
  bmiCategory: string;
}

// AI Generated Response Structure
export interface SupplementRecommendation {
  name: string;
  reason: string;
  caution: string; // Safety note
  priority: 'High' | 'Medium' | 'Low';
}

export interface Habit {
  id: string;
  title: string;
  description: string;
  category: 'Nutrition' | 'Sleep' | 'Movement' | 'Mindfulness';
  xpReward: number;
}

export interface WellnessPlan {
  summary: string;
  nutritionFocus: string; // Food-first advice
  nutritionGaps: string[];
  safeSupplements: SupplementRecommendation[];
  dailyQuests: Habit[];
  safetyDisclaimer: string; // AI generated context-specific disclaimer
}

export interface GamificationState {
  xp: number;
  level: number;
  streak: number;
  completedQuestIds: string[]; // Resets daily in a real app
  badges: string[];
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, WellnessPlan } from "../types";

// NOTE: In a production app, the API key should be proxy-ed through a backend.
// For this frontend-only demo, we use the env variable directly.
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

const wellnessPlanSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    summary: {
      type: Type.STRING,
      description: "A motivating, 2-sentence summary of the user's path forward.",
    },
    nutritionFocus: {
      type: Type.STRING,
      description: "Primary food-first nutritional strategy (e.g., 'Focus on high protein breakfast...').",
    },
    nutritionGaps: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Potential nutrient gaps based on diet/restrictions (e.g., 'Iron due to vegan diet').",
    },
    safeSupplements: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          reason: { type: Type.STRING },
          caution: { type: Type.STRING },
          priority: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
        },
        required: ["name", "reason", "caution", "priority"],
      },
      description: "Evidence-based, safe supplement suggestions only. Empty if high risk.",
    },
    dailyQuests: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          category: { type: Type.STRING, enum: ["Nutrition", "Sleep", "Movement", "Mindfulness"] },
          xpReward: { type: Type.INTEGER },
        },
        required: ["id", "title", "description", "category", "xpReward"],
      },
      description: "3-5 actionable daily habits.",
    },
    safetyDisclaimer: {
      type: Type.STRING,
      description: "Specific safety warning based on user input (e.g., 'Consult OBGYN due to pregnancy').",
    },
  },
  required: ["summary", "nutritionFocus", "nutritionGaps", "safeSupplements", "dailyQuests", "safetyDisclaimer"],
};

export const generateWellnessPlan = async (profile: UserProfile): Promise<WellnessPlan> => {
  const prompt = `
    You are VitalQuest, an evidence-based wellness assistant. 
    Analyze this user profile and generate a JSON wellness plan.

    User Profile:
    - Age: ${profile.age}
    - Gender: ${profile.gender}
    - Height: ${profile.heightCm}cm
    - Weight: ${profile.weightKg}kg
    - Activity: ${profile.activityLevel}
    - Goal: ${profile.goal}
    - Restrictions: ${profile.dietaryRestrictions.join(', ')}
    - Sleep: ${profile.sleepHours} hours
    - Medical/Meds: ${profile.medicationsOrConditions || 'None'}

    SAFETY RULES (CRITICAL):
    1. This is NOT medical advice.
    2. If Age < 18: Focus purely on food, sleep, and activity. NO supplements.
    3. If Pregnancy/Medical Conditions/Medications mentioned: Recommend consulting a doctor. Focus on lifestyle. NO supplements unless extremely benign (like hydration).
    4. Supplements: Only recommend evidence-based options (Creatine, Whey, Vitamin D with test, Omega-3). Avoid risky/proprietary blends.
    5. Always prioritize "Food First".

    OUTPUT:
    Return pure JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: wellnessPlanSchema,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for faster simple JSON tasks, or enable for complex reasoning
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as WellnessPlan;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback in case of API failure or content policy block
    return {
      summary: "We encountered an issue generating your custom plan. Please try again later.",
      nutritionFocus: "Focus on whole foods, balanced meals, and adequate hydration.",
      nutritionGaps: [],
      safeSupplements: [],
      dailyQuests: [
        { id: 'hydration', title: 'Drink Water', description: 'Drink 2L of water today', category: 'Nutrition', xpReward: 10 },
        { id: 'walk', title: 'Take a Walk', description: 'Go for a 15 min walk', category: 'Movement', xpReward: 20 }
      ],
      safetyDisclaimer: "System Error: Could not verify safety constraints. Please consult a doctor."
    };
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-xl font-bold transition-all duration-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-brand-500 hover:bg-brand-600 text-white shadow-lg shadow-brand-500/30 border-b-4 border-brand-700 active:border-b-0 active:translate-y-1",
    secondary: "bg-accent-500 hover:bg-accent-600 text-white shadow-lg shadow-accent-500/30 border-b-4 border-accent-600 active:border-b-0 active:translate-y-1",
    outline: "border-2 border-slate-200 hover:border-brand-500 text-slate-600 hover:text-brand-600 bg-white",
    ghost: "text-slate-500 hover:text-slate-800 hover:bg-slate-100"
  };

  const width = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${width} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useState } from 'react';
import { ActivityLevel, DietaryRestriction, Gender, Goal, UserProfile } from '../types';
import { Button } from './ui/Button';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
  isLoading: boolean;
}

const steps = [
  'Basics',
  'Body',
  'Lifestyle',
  'Medical'
];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, isLoading }) => {
  const [step, setStep] = useState(0);
  const [profile, setProfile] = useState<Partial<UserProfile>>({
    dietaryRestrictions: [],
    gender: Gender.PreferNotToSay,
    activityLevel: ActivityLevel.Sedentary,
    goal: Goal.GeneralHealth
  });

  const handleNext = () => {
    if (step < steps.length - 1) {
      setStep(step + 1);
    } else {
      onComplete(profile as UserProfile);
    }
  };

  const handleBack = () => {
    if (step > 0) setStep(step - 1);
  };

  const updateProfile = (key: keyof UserProfile, value: any) => {
    setProfile(prev => ({ ...prev, [key]: value }));
  };

  const toggleRestriction = (r: DietaryRestriction) => {
    const current = profile.dietaryRestrictions || [];
    if (current.includes(r)) {
      updateProfile('dietaryRestrictions', current.filter(i => i !== r));
    } else {
      updateProfile('dietaryRestrictions', [...current, r]);
    }
  };

  const renderStep = () => {
    switch (step) {
      case 0:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Let's start with the basics</h2>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Age</label>
              <input 
                type="number" 
                value={profile.age || ''} 
                onChange={e => updateProfile('age', parseInt(e.target.value))}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                placeholder="Years"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Gender</label>
              <div className="flex gap-2">
                {[Gender.Male, Gender.Female, Gender.PreferNotToSay].map(g => (
                  <button
                    key={g}
                    onClick={() => updateProfile('gender', g)}
                    className={`flex-1 py-3 rounded-xl border-2 font-medium transition-colors ${
                      profile.gender === g 
                        ? 'border-brand-500 bg-brand-50 text-brand-700' 
                        : 'border-slate-200 hover:border-brand-300'
                    }`}
                  >
                    {g === Gender.PreferNotToSay ? 'Other' : g}
                  </button>
                ))}
              </div>
            </div>
          </div>
        );
      case 1:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Body Metrics</h2>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Height (cm)</label>
              <input 
                type="number" 
                value={profile.heightCm || ''} 
                onChange={e => updateProfile('heightCm', parseInt(e.target.value))}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                placeholder="175"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Weight (kg)</label>
              <input 
                type="number" 
                value={profile.weightKg || ''} 
                onChange={e => updateProfile('weightKg', parseInt(e.target.value))}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                placeholder="70"
              />
            </div>
          </div>
        );
      case 2:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Your Goals & Lifestyle</h2>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Main Goal</label>
              <select 
                value={profile.goal} 
                onChange={e => updateProfile('goal', e.target.value)}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none bg-white"
              >
                {Object.values(Goal).map(g => <option key={g} value={g}>{g}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Activity Level</label>
              <select 
                value={profile.activityLevel} 
                onChange={e => updateProfile('activityLevel', e.target.value)}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none bg-white"
              >
                {Object.values(ActivityLevel).map(a => <option key={a} value={a}>{a}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Sleep (Avg Hours)</label>
               <input 
                type="number" 
                value={profile.sleepHours || ''} 
                onChange={e => updateProfile('sleepHours', parseInt(e.target.value))}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none"
                placeholder="7"
              />
            </div>
          </div>
        );
      case 3:
        return (
           <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Final Safety Checks</h2>

            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Dietary Restrictions</label>
              <div className="flex flex-wrap gap-2">
                {Object.values(DietaryRestriction).map(r => (
                  <button
                    key={r}
                    onClick={() => toggleRestriction(r)}
                    className={`px-4 py-2 rounded-full text-sm font-bold border-2 transition-colors ${
                      profile.dietaryRestrictions?.includes(r)
                        ? 'border-brand-500 bg-brand-100 text-brand-700'
                        : 'border-slate-200 text-slate-500 hover:border-brand-200'
                    }`}
                  >
                    {r}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">
                Medical Conditions / Medications
                <span className="block text-xs font-normal text-slate-400">Optional. Enter "None" if healthy. If you are pregnant or have a chronic condition, please list it here so we can keep recommendations safe.</span>
              </label>
              <textarea 
                value={profile.medicationsOrConditions || ''} 
                onChange={e => updateProfile('medicationsOrConditions', e.target.value)}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none"
                placeholder="e.g. Type 2 Diabetes, Pregnant, taking Blood Thinners..."
                rows={3}
              />
            </div>
          </div>
        );
      default: return null;
    }
  };

  const isStepValid = () => {
    if (step === 0) return profile.age && profile.age > 0;
    if (step === 1) return profile.heightCm && profile.weightKg;
    if (step === 2) return profile.goal && profile.activityLevel && profile.sleepHours;
    return true;
  };

  return (
    <div className="max-w-xl mx-auto p-6">
      {/* Progress Bar */}
      <div className="flex gap-2 mb-8">
        {steps.map((_, i) => (
          <div key={i} className={`h-2 flex-1 rounded-full transition-colors ${i <= step ? 'bg-brand-500' : 'bg-slate-200'}`} />
        ))}
      </div>

      <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100 min-h-[400px] flex flex-col justify-between">
        {renderStep()}

        <div className="flex gap-4 mt-8 pt-6 border-t border-slate-100">
          {step > 0 && (
            <Button variant="ghost" onClick={handleBack} disabled={isLoading}>
              Back
            </Button>
          )}
          <Button 
            fullWidth 
            onClick={handleNext} 
            disabled={!isStepValid() || isLoading}
            variant="primary"
          >
            {isLoading ? 'Generating Plan...' : step === steps.length - 1 ? 'Create My Plan' : 'Next'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { SupplementRecommendation, WellnessPlan, Habit } from '../types';

interface PlanDisplayProps {
  plan: WellnessPlan;
}

const SupplementCard: React.FC<{ supp: SupplementRecommendation }> = ({ supp }) => (
  <div className="bg-white border-l-4 border-brand-500 p-4 rounded-r-xl shadow-sm mb-3">
    <div className="flex justify-between items-start">
      <h4 className="font-bold text-lg text-slate-800">{supp.name}</h4>
      <span className={`text-xs px-2 py-1 rounded-full font-bold ${
        supp.priority === 'High' ? 'bg-brand-100 text-brand-700' : 'bg-slate-100 text-slate-600'
      }`}>
        {supp.priority} Priority
      </span>
    </div>
    <p className="text-sm text-slate-600 mt-1">{supp.reason}</p>
    {supp.caution && (
      <div className="mt-2 text-xs text-amber-600 bg-amber-50 p-2 rounded">
        <strong>⚠️ Note:</strong> {supp.caution}
      </div>
    )}
  </div>
);

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ plan }) => {
  return (
    <div className="space-y-8 animate-fade-in-up">

      {/* Summary Section */}
      <section className="bg-gradient-to-br from-brand-500 to-brand-600 rounded-3xl p-8 text-white shadow-lg">
        <h2 className="text-2xl font-extrabold mb-4">Your Path Forward</h2>
        <p className="text-lg opacity-95 leading-relaxed font-medium">{plan.summary}</p>
      </section>

      <div className="grid md:grid-cols-2 gap-6">
        {/* Nutrition First */}
        <section className="bg-slate-50 rounded-3xl p-6 border-2 border-slate-100">
          <div className="flex items-center gap-3 mb-4">
             <div className="w-10 h-10 bg-green-100 rounded-full flex items-center justify-center text-xl">🥗</div>
             <h3 className="text-xl font-bold text-slate-800">Nutrition Strategy</h3>
          </div>
          <p className="text-slate-700 mb-6 font-medium">{plan.nutritionFocus}</p>

          {plan.nutritionGaps.length > 0 && (
            <div className="bg-white rounded-xl p-4 shadow-sm">
              <h4 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-2">Watch Out For Gaps</h4>
              <ul className="list-disc list-inside text-slate-700 space-y-1">
                {plan.nutritionGaps.map((gap, i) => (
                  <li key={i}>{gap}</li>
                ))}
              </ul>
            </div>
          )}
        </section>

        {/* Supplementation */}
        <section className="bg-slate-50 rounded-3xl p-6 border-2 border-slate-100">
           <div className="flex items-center gap-3 mb-4">
             <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center text-xl">💊</div>
             <h3 className="text-xl font-bold text-slate-800">Safe Supplementation</h3>
          </div>
          <p className="text-xs text-slate-500 mb-4">
            Supplements are secondary to food. Only considered if evidence-based and safe for you.
          </p>
          {plan.safeSupplements.length === 0 ? (
             <div className="p-4 bg-green-50 text-green-800 rounded-xl text-center">
               Great news! Based on your profile, you likely don't need any specific supplements right now. Focus on whole foods.
             </div>
          ) : (
            <div>
              {plan.safeSupplements.map((supp, i) => (
                <SupplementCard key={i} supp={supp} />
              ))}
            </div>
          )}
        </section>
      </div>

       {/* Safety Disclaimer Banner */}
       <div className="bg-slate-900 rounded-2xl p-6 text-slate-300 text-sm flex gap-4 items-start">
         <span className="text-2xl">⚖️</span>
         <div>
           <strong className="text-white block mb-1">Important Safety Note</strong>
           {plan.safetyDisclaimer}
           <br/>
           <span className="opacity-70 mt-2 block">Content generated by VitalQuest is for informational purposes only and does not constitute medical advice, diagnosis, or treatment.</span>
         </div>
       </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CalculatedMetrics, GamificationState, UserProfile, WellnessPlan, Habit } from '../types';
import { PlanDisplay } from './PlanDisplay';
import { Button } from './ui/Button';

interface DashboardProps {
  profile: UserProfile;
  metrics: CalculatedMetrics;
  plan: WellnessPlan;
  gamification: GamificationState;
  onUpdateGamification: (newState: GamificationState) => void;
  onReset: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  profile, 
  metrics, 
  plan, 
  gamification, 
  onUpdateGamification,
  onReset
}) => {
  const [activeTab, setActiveTab] = useState<'plan' | 'quests'>('plan');

  const completeQuest = (questId: string, xpReward: number) => {
    if (gamification.completedQuestIds.includes(questId)) return;

    // Play sound or confetti effect here in a full app
    const newXp = gamification.xp + xpReward;
    const newLevel = Math.floor(newXp / 100) + 1;

    onUpdateGamification({
      ...gamification,
      xp: newXp,
      level: newLevel,
      completedQuestIds: [...gamification.completedQuestIds, questId]
    });
  };

  const calculateProgress = () => {
    const total = plan.dailyQuests.length;
    const completed = gamification.completedQuestIds.length;
    return total === 0 ? 0 : Math.round((completed / total) * 100);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 pb-20">

      {/* Gamification Header */}
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-100 mb-6 gap-4">
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="w-12 h-12 bg-amber-100 rounded-full flex items-center justify-center text-2xl shadow-inner">
            ⚡
          </div>
          <div>
            <h2 className="font-bold text-slate-800 text-lg">Level {gamification.level}</h2>
            <div className="w-32 h-2 bg-slate-100 rounded-full mt-1 overflow-hidden">
              <div 
                className="h-full bg-amber-400 transition-all duration-500" 
                style={{ width: `${gamification.xp % 100}%` }} 
              />
            </div>
            <p className="text-xs text-slate-500 mt-1">{gamification.xp % 100} / 100 XP to next level</p>
          </div>
        </div>

        <div className="flex gap-6 text-center">
            <div>
                <span className="block text-xl font-black text-brand-600">{gamification.streak} 🔥</span>
                <span className="text-xs font-bold text-slate-400 uppercase">Day Streak</span>
            </div>
             <div>
                <span className="block text-xl font-black text-slate-800">{Math.round(metrics.tdee)}</span>
                <span className="text-xs font-bold text-slate-400 uppercase">Daily Cals</span>
            </div>
             <div>
                <span className="block text-xl font-black text-slate-800">{metrics.bmi.toFixed(1)}</span>
                <span className="text-xs font-bold text-slate-400 uppercase">BMI</span>
            </div>
        </div>
      </header>

      {/* Tabs */}
      <div className="flex gap-2 mb-6 bg-slate-100 p-1 rounded-xl w-fit mx-auto md:mx-0">
        <button 
          onClick={() => setActiveTab('plan')}
          className={`px-6 py-2 rounded-lg font-bold text-sm transition-all ${activeTab === 'plan' ? 'bg-white shadow text-brand-600' : 'text-slate-500 hover:text-slate-700'}`}
        >
          My Plan
        </button>
        <button 
          onClick={() => setActiveTab('quests')}
          className={`px-6 py-2 rounded-lg font-bold text-sm transition-all ${activeTab === 'quests' ? 'bg-white shadow text-brand-600' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Daily Quests
          {plan.dailyQuests.length - gamification.completedQuestIds.length > 0 && (
             <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">
               {plan.dailyQuests.length - gamification.completedQuestIds.length}
             </span>
          )}
        </button>
      </div>

      {activeTab === 'plan' && <PlanDisplay plan={plan} />}

      {activeTab === 'quests' && (
        <div className="space-y-4 animate-fade-in">
          <div className="flex justify-between items-end mb-2">
            <h3 className="text-xl font-bold text-slate-800">Today's Goals</h3>
            <span className="text-sm font-semibold text-brand-600">{calculateProgress()}% Complete</span>
          </div>

          {/* Progress Bar */}
          <div className="h-4 bg-slate-200 rounded-full overflow-hidden mb-6">
             <div 
               className="h-full bg-brand-500 transition-all duration-1000 ease-out"
               style={{ width: `${calculateProgress()}%` }}
             />
          </div>

          <div className="grid gap-4">
            {plan.dailyQuests.map(quest => {
              const isCompleted = gamification.completedQuestIds.includes(quest.id);
              return (
                <div 
                  key={quest.id} 
                  onClick={() => !isCompleted && completeQuest(quest.id, quest.xpReward)}
                  className={`relative p-5 rounded-2xl border-2 transition-all cursor-pointer group
                    ${isCompleted 
                      ? 'bg-brand-50 border-brand-200 opacity-60' 
                      : 'bg-white border-slate-200 hover:border-brand-400 hover:shadow-md'
                    }`}
                >
                  <div className="flex items-start gap-4">
                    <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center text-white transition-colors
                      ${isCompleted ? 'bg-brand-500 border-brand-500' : 'border-slate-300 group-hover:border-brand-400'}`}>
                      {isCompleted && '✓'}
                    </div>
                    <div className="flex-1">
                      <h4 className={`font-bold text-lg ${isCompleted ? 'text-brand-800 line-through' : 'text-slate-800'}`}>{quest.title}</h4>
                      <p className="text-slate-500 text-sm">{quest.description}</p>
                    </div>
                    <div className="text-amber-500 font-bold text-sm bg-amber-50 px-2 py-1 rounded-lg">
                      +{quest.xpReward} XP
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {calculateProgress() === 100 && (
            <div className="mt-8 p-6 bg-gradient-to-r from-yellow-100 to-amber-100 rounded-2xl text-center border border-yellow-200 animate-bounce-slow">
              <div className="text-4xl mb-2">🎉</div>
              <h3 className="text-xl font-black text-yellow-800">All Quests Complete!</h3>
              <p className="text-yellow-700">You're crushing it! Come back tomorrow to keep the streak alive.</p>
            </div>
          )}
        </div>
      )}

      <div className="mt-12 text-center">
         <Button variant="ghost" onClick={onReset} className="text-slate-400 text-sm">Start Over (Debug)</Button>
      </div>

    </div>
  );
};

import React, { useState } from 'react';
