import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, WellnessPlan, FoodItem } from "../types";

// NOTE: In a production app, the API key should be proxy-ed through a backend.
// For this frontend-only demo, we use the env variable directly.
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

const wellnessPlanSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    summary: {
      type: Type.STRING,
      description: "A motivating, 2-sentence summary of the user's path forward.",
    },
    nutritionFocus: {
      type: Type.STRING,
      description: "Primary food-first nutritional strategy (e.g., 'Focus on high protein breakfast...').",
    },
    nutritionGaps: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "Potential nutrient gaps based on diet/restrictions (e.g., 'Iron due to vegan diet').",
    },
    safeSupplements: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          reason: { type: Type.STRING },
          caution: { type: Type.STRING },
          priority: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
        },
        required: ["name", "reason", "caution", "priority"],
      },
      description: "Evidence-based, safe supplement suggestions only. Empty if high risk.",
    },
    dailyQuests: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
