export const parseFoodLog = async (input: string): Promise<FoodItem[]> => {
  const prompt = `
    Analyze this food log text and break it down into items with estimated nutrition data.
    Input: "${input}"

    Rules:
    - Estimate portion sizes based on context or use standard averages.
    - Output macros in grams, calories in kcal.
    - For 'micros', include ESTIMATED values for the following nutrients if present:
      Fiber, Omega-3, Calcium, Iron, Magnesium, Zinc, Sodium, Potassium, Phosphorus, Manganese, Selenium, Chromium, Molybdenum, Iodine, Vitamin A, C, D, E, K, Thiamin, Riboflavin, Niacin, B6, Folate, B12, Biotin, Pantothenic Acid, Choline.

    - IMPORTANT: Use these units for 'amount':
      - g: Fiber, Omega-3
      - mg: Calcium, Iron, Magnesium, Zinc, Sodium, Potassium, Phosphorus, Manganese, Vitamin C, Thiamin, Riboflavin, Niacin, B6, Pantothenic Acid, Choline, Vitamin E
      - mcg: Selenium, Chromium, Molybdenum, Iodine, Vitamin A, D, K, B12, Folate, Biotin

    - Be reasonably accurate but conservative. Return empty list if no food detected.
  `;

  try {
     const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: foodParseSchema,
      },
    });

    const text = response.text;
    if(!text) return [];

    const data = JSON.parse(text);
    return data.foods.map((f: any, i: number) => {
      // Transform micros array back to map for the app's data model
      const microsMap: Record<string, number> = {};
      if (Array.isArray(f.micros)) {
        f.micros.forEach((m: {name: string, amount: number}) => {
          const normalizedName = NUTRIENT_ALIASES[m.name] || m.name;
          microsMap[normalizedName] = m.amount;
        });
      }

      return {
        id: `ai-${Date.now()}-${i}`,
        name: f.name,
        calories: f.calories,
        protein: f.protein,
        carbs: f.carbs,
        fat: f.fat,
        micros: microsMap
      };
    });

  } catch (error) {
    console.error("Error parsing food", error);
    return [];
  }
}

