export const generateWellnessPlan = async (profile: UserProfile): Promise<WellnessPlan> => {
  const prompt = `
    You are VitalQuest, an evidence-based wellness assistant. 
    Analyze this user profile and generate a JSON wellness plan.

    User Profile:
    - Age: ${profile.age}
    - Gender: ${profile.gender}
    - Height: ${profile.heightCm}cm
    - Weight: ${profile.weightKg}kg
    - Activity: ${profile.activityLevel}
    - Goal: ${profile.goal}
    - Restrictions: ${profile.dietaryRestrictions.join(', ')}
    - Sleep: ${profile.sleepHours} hours
    - Medical/Meds: ${profile.medicationsOrConditions || 'None'}

    SAFETY RULES (CRITICAL):
    1. This is NOT medical advice.
    2. If Age < 18: Focus purely on food, sleep, and activity. NO supplements.
    3. If Pregnancy/Medical Conditions/Medications mentioned: Recommend consulting a doctor. Focus on lifestyle. NO supplements unless extremely benign (like hydration).
    4. Supplements: Only recommend evidence-based options (Creatine, Whey, Vitamin D with test, Omega-3). Avoid risky/proprietary blends.
    5. Always prioritize "Food First".

    OUTPUT:
    Return pure JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: wellnessPlanSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as WellnessPlan;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback in case of API failure or content policy block
    return {
      summary: "We encountered an issue generating your custom plan. Please try again later.",
      currentStrengths: ["Commitment to health"],
      areasForImprovement: ["Consistency", "Nutrient tracking"],
      nutritionFocus: "Focus on whole foods, balanced meals, and adequate hydration.",
      nutritionGaps: [],
      safeSupplements: [],
      dailyQuests: [
        { id: 'hydration', title: 'Drink Water', description: 'Drink 2L of water today', category: 'Nutrition', xpReward: 10 },
        { id: 'walk', title: 'Take a Walk', description: 'Go for a 15 min walk', category: 'Movement', xpReward: 20 }
      ],
      safetyDisclaimer: "System Error: Could not verify safety constraints. Please consult a doctor."
    };
  }
};

