                         <div className="text-xs font-bold text-slate-400 uppercase mb-1 truncate w-full" title={key}>{key}</div>

                         <div>
                            <div className="text-lg font-black text-slate-800 flex items-baseline gap-0.5">
                              {amount > 0 ? Math.round(amount * 10) / 10 : '-'}
                              {unit && <span className="text-xs font-normal text-slate-500">{unit}</span>}
                            </div>

                            {target && amount > 0 && (
                                <div className={`text-xs font-bold mt-1 ${
                                    (amount / target) > 1.2 ? 'text-amber-500' : 
                                    (amount / target) > 0.8 ? 'text-green-500' : 'text-slate-400'
                                }`}>
                                    {Math.round((amount / target) * 100)}% DV
                                </div>
                            )}
                         </div>
                      </button>
                    )
                 })}
              </div>
           </section>

           <NutrientDetailModal />
        </div>
      )}
    </div>
  );
};

