export const generateWellnessPlan = async (profile: UserProfile): Promise<WellnessPlan> => {
  const prompt = `
    You are VitalQuest, an evidence-based wellness assistant. 
    Analyze this user profile and generate a JSON wellness plan.

    User Profile:
    - Age: ${profile.age}
    - Gender: ${profile.gender}
    - Height: ${profile.heightCm}cm
    - Weight: ${profile.weightKg}kg
    - Activity: ${profile.activityLevel}
    - Goal: ${profile.goal}
    - Restrictions: ${profile.dietaryRestrictions.join(', ')}
    - Sleep: ${profile.sleepHours} hours
    - Medical/Meds: ${profile.medicationsOrConditions || 'None'}

    SAFETY RULES (CRITICAL):
    1. This is NOT medical advice.
    2. If Age < 18: Focus purely on food, sleep, and activity. NO supplements.
    3. If Pregnancy/Medical Conditions/Medications mentioned: Recommend consulting a doctor. Focus on lifestyle. NO supplements unless extremely benign (like hydration).
    4. Supplements: Only recommend evidence-based options (Creatine, Whey, Vitamin D with test, Omega-3). Avoid risky/proprietary blends.
    5. Always prioritize "Food First".

    OUTPUT:
    Return pure JSON matching the schema.
  `;

  try {
    const response = await retryWithBackoff(async () => {
      return await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: wellnessPlanSchema,
        },
      });
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as WellnessPlan;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback in case of API failure or content policy block
    return {
      summary: "We encountered an issue generating your custom plan. Please try again later.",
      currentStrengths: ["Commitment to health"],
      areasForImprovement: ["Consistency", "Nutrient tracking"],
      nutritionFocus: "Focus on whole foods, balanced meals, and adequate hydration.",
      nutritionGaps: [],
      safeSupplements: [],
      dailyQuests: [
        { id: 'hydration', title: 'Drink Water', description: 'Drink 2L of water today', category: 'Nutrition', xpReward: 10 },
        { id: 'walk', title: 'Take a Walk', description: 'Go for a 15 min walk', category: 'Movement', xpReward: 20 }
      ],
      safetyDisclaimer: "System Error: Could not verify safety constraints. Please consult a doctor."
    };
  }
};

const foodParseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    foods: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          servingSize: { 
            type: Type.STRING,
            description: "The quantity used for calculation, e.g., '200g', '1 cup', '3 slices'."
          },
          calories: { type: Type.NUMBER },
          protein: { type: Type.NUMBER },
          carbs: { type: Type.NUMBER },
          fat: { type: Type.NUMBER },
          micros: { 
            type: Type.ARRAY,
            description: "List of key micronutrients.",
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING, description: "Nutrient name (e.g. 'Vitamin C', 'Biotin')"},
                amount: { type: Type.NUMBER, description: "Amount value (number only)" }
              },
              required: ["name", "amount"]
            }
          }
        },
        required: ["name", "servingSize", "calories", "protein", "carbs", "fat", "micros"],
      }
    }
  }
};

const NUTRIENT_ALIASES: Record<string, string> = {
  "Vitamin B1": "Thiamin",
  "Thiamine": "Thiamin",
  "Vitamin B2": "Riboflavin",
  "Vitamin B3": "Niacin",
  "Vitamin B5": "Pantothenic Acid",
  "Vitamin B7": "Biotin",
  "Vit B7": "Biotin",
  "Vitamin H": "Biotin",
  "Folic Acid": "Folate",
  "Vitamin B9": "Folate",
  "Omega 3": "Omega-3",
  "Omega-3 Fatty Acids": "Omega-3",
  "Phosphorous": "Phosphorus",
  "B6": "Vitamin B6",
  "Vitamin B-6": "Vitamin B6",
  "B12": "Vitamin B12",
  "Vitamin B-12": "Vitamin B12",
  "Vit A": "Vitamin A",
  "Vit C": "Vitamin C",
  "Vit D": "Vitamin D",
  "Vit E": "Vitamin E",
  "Vit K": "Vitamin K",
  "Sugars": "Sugar",
  "Added Sugars": "Sugar",
  "Total Sugar": "Sugar",
  "Cu": "Copper",
  "Zn": "Zinc",
  "Mg": "Magnesium",
  "Ca": "Calcium",
  "Fe": "Iron",
  "K": "Potassium",
  "Na": "Sodium",
  "Mn": "Manganese",
  "Se": "Selenium",
  "Cr": "Chromium",
  "Chromium (Cr)": "Chromium",
  "Mo": "Molybdenum",
  "Molybdenum (Mo)": "Molybdenum",
  "I": "Iodine",
  "Iodine (I)": "Iodine"
};

export const parseFoodLog = async (input: string): Promise<FoodItem[]> => {
  const prompt = `
    Analyze this food log text and break it down into items with estimated nutrition data.
    Input: "${input}"

    Rules:
    - User may provide specific quantities (e.g. "100g", "4oz", "1lb", "200ml", "1 cup", "1 slice"). You MUST calculate nutrition based on these exact amounts.
    - EXTRACT the 'servingSize' explicitly (e.g., if input is "200g chicken", servingSize is "200g").
    - If no quantity is specified, use standard portion averages and state it (e.g. "1 medium").
    - Output macros in grams, calories in kcal.
    - For 'micros', include ESTIMATED values for the following nutrients if present. Be sure to include TRACE MINERALS if applicable:
      Fiber, Sugar, Omega-3, Calcium, Iron, Magnesium, Zinc, Copper, Sodium, Potassium, Phosphorus, Manganese, Selenium, Chromium, Molybdenum, Iodine, Vitamin A, C, D, E, K, Thiamin, Riboflavin, Niacin, Vitamin B6, Folate, Vitamin B12, Biotin, Pantothenic Acid, Choline.

    - EXPLICIT INSTRUCTION: Ensure you estimate values for Chromium, Molybdenum, and Biotin if the food is a known source (e.g. oats, nuts, eggs, broccoli), do not omit them.

    - IMPORTANT: Use these units for 'amount':
      - g: Fiber, Omega-3, Sugar
      - mg: Calcium, Iron, Magnesium, Zinc, Sodium, Potassium, Phosphorus, Manganese, Copper, Vitamin C, Thiamin, Riboflavin, Niacin, Vitamin B6, Pantothenic Acid, Choline, Vitamin E
      - mcg: Selenium, Chromium, Molybdenum, Iodine, Vitamin A, D, K, Vitamin B12, Folate, Biotin

    - Be reasonably accurate but conservative. Return empty list if no food detected.
  `;

  try {
     const response = await retryWithBackoff(async () => {
       return await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: foodParseSchema,
        },
      });
     });

    const text = response.text;
    if(!text) return [];

    const data = JSON.parse(text);
    return data.foods.map((f: any, i: number) => {
      // Transform micros array back to map for the app's data model
      const microsMap: Record<string, number> = {};
      if (Array.isArray(f.micros)) {
        f.micros.forEach((m: {name: string, amount: number}) => {
          const normalizedName = NUTRIENT_ALIASES[m.name] || m.name;
          microsMap[normalizedName] = m.amount;
        });
      }

      return {
        id: `ai-${Date.now()}-${i}`,
        name: f.name,
        servingSize: f.servingSize || "Standard Serving",
        calories: f.calories,
        protein: f.protein,
        carbs: f.carbs,
        fat: f.fat,
        micros: microsMap
      };
    });

  } catch (error) {
    console.error("Error parsing food", error);
    return [];
  }
}

