// services/storageService.ts
import { UserProfile, CalculatedMetrics, WellnessPlan, MealLog, GamificationState, MicronutrientScoreHistory } from '../types';

const STORAGE_KEY = 'vitalquest_state_v1';
const SCHEMA_VERSION = 'v1';

export interface AppState {
  profile: UserProfile | null;
  metrics: CalculatedMetrics | null;
  plan: WellnessPlan | null;
  foodLogs: MealLog[];
  gamification: GamificationState;
  scoreHistory: MicronutrientScoreHistory;
}

interface StoragePayload {
  version: string;
  savedAt: number;
  data: AppState;
}

let saveTimeout: any;

export const loadState = (): AppState | null => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;

    const parsed = JSON.parse(raw) as StoragePayload;
    if (parsed.version !== SCHEMA_VERSION) {
      console.warn("Schema version mismatch, resetting state.");
      return null;
    }

    return parsed.data;
  } catch (e) {
    console.error("Failed to load state", e);
    return null;
  }
};

export const saveState = (state: AppState) => {
  if (saveTimeout) clearTimeout(saveTimeout);

  // Debounce 1s
  saveTimeout = setTimeout(() => {
    try {
      const payload: StoragePayload = {
        version: SCHEMA_VERSION,
        savedAt: Date.now(),
        data: state
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(payload));
    } catch (e) {
      console.error("Failed to save state", e);
    }
  }, 1000);
};

export const clearState = () => {
  localStorage.removeItem(STORAGE_KEY);
};
