// utils/micronutrientScore.ts
import { MealLog, MicronutrientScoreBreakdown, MicronutrientScoreResult, FoodItem, NutrientEducation } from '../types';
import { NUTRIENT_INFO } from '../data/nutrientData';

export const PRIORITY_MICROS = [
  "Fiber", "Potassium", "Magnesium", "Iron", "Vitamin D", "Vitamin B12", "Calcium", "Vitamin C", "Zinc", "Folate"
];

const BADGE_TITLES: Record<string, string> = {
  "Fiber": "Fiber Hero",
  "Potassium": "Potassium Power",
  "Magnesium": "Magnesium Master",
  "Iron": "Iron Man/Woman",
  "Vitamin D": "Sunshine Soul",
  "Vitamin B12": "Energy Expert",
  "Calcium": "Bone Builder",
  "Vitamin C": "Immunity Idol",
  "Zinc": "Zinc Zenith",
  "Folate": "Folate Friend"
};

export const calculateMicronutrientScore = (logs: MealLog[]): MicronutrientScoreResult => {
  // 1. Aggregate consumed micros
  const consumed: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumed[name] = (consumed[name] || 0) + (amount as number);
      });
    }
  });

  let totalPoints = 0;
  const breakdown: MicronutrientScoreBreakdown[] = [];
  const newBadges: string[] = [];

  // 2. Score each priority micro
  PRIORITY_MICROS.forEach(micro => {
    const info = NUTRIENT_INFO[micro];
    if (!info || !info.targetVal) return;

    const current = consumed[micro] || 0;
    const target = info.targetVal;
    const pct = current / target;

    let points = 0;
    let status: 'low' | 'medium' | 'high' = 'low';

    if (pct >= 0.8) {
      points = 10;
      status = 'high';
      // Unlock badge candidate
      const badgeName = BADGE_TITLES[micro];
      if (badgeName) newBadges.push(badgeName);
    } else if (pct >= 0.5) {
      points = 5;
      status = 'medium';
    }

    totalPoints += points;
    breakdown.push({
      nutrient: micro,
      current,
      target,
      status,
      points
    });
  });

  // Clamp 0-100
  const score = Math.min(100, Math.max(0, totalPoints));

  return {
    score,
    breakdown,
    newBadges
  };
};

export const getSmartSubstitutions = (
    nutrient: string, 
    dietaryRestrictions: string[], 
    commonFoods: FoodItem[]
): { food: FoodItem, tip: string }[] => {
    // Filter foods by restriction
    const safeFoods = commonFoods.filter(f => {
        const tags = f.tags || [];
        if (dietaryRestrictions.includes('Vegan')) {
            if (tags.includes('Animal') || tags.includes('Dairy') || tags.includes('Egg') || tags.includes('Fish') || tags.includes('Meat')) return false;
        }
        if (dietaryRestrictions.includes('Vegetarian')) {
             if (tags.includes('Meat') || tags.includes('Fish')) return false;
        }
        if (dietaryRestrictions.includes('Lactose-Free')) {
             if (tags.includes('Dairy')) return false;
        }
        if (dietaryRestrictions.includes('Gluten-Free')) {
            if (tags.includes('Gluten')) return false;
        }
        return true;
    });

    // Find foods high in this nutrient
    const candidates = safeFoods
        .map(f => ({
            food: f,
            amount: f.micros?.[nutrient] || 0
        }))
        .filter(c => c.amount > 0)
        .sort((a, b) => b.amount - a.amount)
        .slice(0, 3);

    return candidates.map(c => ({
        food: c.food,
        tip: `Add ${c.food.servingSize} for +${Math.round(c.amount)}${NUTRIENT_INFO[nutrient]?.unit || ''} ${nutrient}`
    }));
};
