// components/NutritionTracker.tsx
import React, { useState, useEffect } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets, MicronutrientScoreResult } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog } from '../services/geminiService';
import { calculateMicronutrientScore, getSmartSubstitutions } from '../utils/micronutrientScore';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (logId: string, updatedFood: FoodItem) => void;
  onDeleteLog: (logId: string) => void;
  onDuplicateLog: (logId: string) => void;
  targets: MacroTargets;
  dietaryRestrictions: string[];
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ 
  logs, onAddFood, onUpdateLog, onDeleteLog, onDuplicateLog, targets, dietaryRestrictions
}) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);

  // Edit Modal State
  const [editLog, setEditLog] = useState<MealLog | null>(null);
  const [editQty, setEditQty] = useState<number>(0);
  const [editUnit, setEditUnit] = useState<string>('');
  const [editBaseQty, setEditBaseQty] = useState<number>(0);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
      });
    }
  });

  const microScore = calculateMicronutrientScore(logs);

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  const openEditModal = (log: MealLog) => {
    setEditLog(log);
    // Try to parse quantity and unit from string like "200g" or "1.5 cup"
    const match = log.food.servingSize?.match(/^(\d+(?:\.\d+)?)\s*([a-zA-Z]+.*)$/);
    if (match) {
        const q = parseFloat(match[1]);
        setEditQty(q);
        setEditBaseQty(q);
        setEditUnit(match[2]);
    } else {
        // Fallback: Treat as 1 "serving"
        setEditQty(1);
        setEditBaseQty(1);
        setEditUnit("serving(s)");
    }
    setMenuOpenId(null);
  };

  const handleSaveEdit = () => {
    if (!editLog) return;
    const ratio = editQty / editBaseQty;

    // Scale nutrients
    const scaledFood: FoodItem = {
        ...editLog.food,
        servingSize: `${Math.round(editQty * 100)/100} ${editUnit}`,
        calories: Math.round(editLog.food.calories * ratio),
        protein: Math.round(editLog.food.protein * ratio * 10) / 10,
        carbs: Math.round(editLog.food.carbs * ratio * 10) / 10,
        fat: Math.round(editLog.food.fat * ratio * 10) / 10,
        micros: {}
    };

    if (editLog.food.micros) {
        scaledFood.micros = {};
        Object.entries(editLog.food.micros).forEach(([k, v]) => {
            scaledFood.micros![k] = (v as number) * ratio;
        });
    }

    onUpdateLog(editLog.id, scaledFood);
    setEditLog(null);
  };

  const adjustEditQty = (delta: number) => {
    setEditQty(prev => Math.max(0, parseFloat((prev + delta).toFixed(2))));
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
    const scoreData = microScore.breakdown.find(b => b.nutrient === selectedNutrient);
    const amount = consumedMicros[selectedNutrient] || 0;

    // Status Logic
    const pct = info.targetVal ? amount / info.targetVal : 0;
    let statusColor = "text-slate-500";
    let statusText = "No Target";
    if (info.targetVal) {
        if (pct < 0.5) { statusText = "Low"; statusColor = "text-amber-500"; }
        else if (pct < 0.8) { statusText = "Improving"; statusColor = "text-yellow-500"; }
        else { statusText = "On Track"; statusColor = "text-green-500"; }
    }

    // Smart Subs
    const suggestions = getSmartSubstitutions(selectedNutrient, dietaryRestrictions, MOCK_COMMON_FOODS);

    return (
      <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4" onClick={() => setSelectedNutrient(null)}>
        <div className="bg-white rounded-3xl p-6 max-w-lg w-full shadow-2xl animate-fade-in max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
          <div className="flex justify-between items-start mb-6">
             <div>
                <h3 className="text-2xl font-black text-slate-800">{selectedNutrient}</h3>
                <p className="text-slate-500 text-sm font-medium">{info.description}</p>
             </div>
             <button onClick={() => setSelectedNutrient(null)} className="text-slate-400 hover:text-slate-800 text-2xl font-bold bg-slate-100 w-10 h-10 rounded-full flex items-center justify-center">×</button>
          </div>

          <div className="grid grid-cols-2 gap-4 mb-8">
             <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                <div className="text-xs text-slate-400 uppercase font-bold">Today</div>
                <div className="text-2xl font-black text-slate-900">
                    {Math.round(amount * 10)/10} <span className="text-sm font-medium text-slate-500">{info.unit}</span>
                </div>
             </div>
             <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                <div className="text-xs text-slate-400 uppercase font-bold">Target</div>
                <div className="flex items-baseline gap-2">
                    <div className="text-2xl font-black text-slate-900">{info.dailyValue}</div>
                </div>
                <div className={`text-xs font-bold mt-1 ${statusColor}`}>● {statusText}</div>
             </div>
          </div>

          <div className="mb-8">
            <h4 className="font-bold text-sm text-slate-800 uppercase mb-3 flex items-center gap-2">
                🌱 Best Sources For You
                <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full border border-slate-200">Filtered</span>
            </h4>
            <div className="flex flex-wrap gap-2">
              {suggestions.map(s => (
                <div key={s.food.id} className="bg-green-50 border border-green-100 rounded-xl p-3 flex-1 min-w-[140px]">
                    <div className="font-bold text-green-900">{s.food.name}</div>
                    <div className="text-xs text-green-700 mt-1">{s.tip}</div>
                </div>
              ))}
              {suggestions.length === 0 && (
                  <p className="text-sm text-slate-500 italic">Check general sources: {info.sources.join(", ")}</p>
              )}
            </div>
          </div>

          {info.caution && (
            <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 text-amber-800 text-xs">
                <strong>⚠️ Note: </strong> {info.caution}
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Sub-tabs */}
      <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
        <button
          onClick={() => setActiveTab('log')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'log' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Food Log
        </button>
        <button
          onClick={() => setActiveTab('analysis')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Analysis & Info
        </button>
      </div>

      {activeTab === 'log' && (
        <div className="animate-fade-in">
          {!isAdding ? (
            <>
              {/* Daily Summary Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
                <div>
                   <h3 className="font-bold text-slate-500 text-sm uppercase">Calories Remaining</h3>
                   <div className="text-4xl font-black text-slate-800">
                     {Math.max(0, Math.round(targets.calories - consumedMacros.calories))}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-sm text-slate-500">Eaten</div>
                   <div className="font-bold text-xl text-brand-600">{Math.round(consumedMacros.calories)} kcal</div>
                </div>
              </div>

              <div className="space-y-6">
                {MEAL_TYPES.map(type => {
                  const mealLogs = logs.filter(l => l.type === type);
                  const mealCals = mealLogs.reduce((acc, l) => acc + l.food.calories, 0);

                  return (
                    <div key={type} className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                      <div className="bg-slate-50 p-4 flex justify-between items-center border-b border-slate-100">
                        <h4 className="font-bold text-slate-800">{type}</h4>
                        <span className="text-sm font-medium text-slate-500">{mealCals} kcal</span>
                      </div>
                      <div className="divide-y divide-slate-100">
                        {mealLogs.length === 0 ? (
                          <div className="p-4 text-center text-slate-400 text-sm italic">No food logged</div>
                        ) : (
                          mealLogs.map(log => (
                            <div key={log.id} className="relative p-4 flex justify-between items-center hover:bg-slate-50 transition-colors group">
                               <div>
                                 <div className="font-medium text-slate-800 flex items-center gap-2">
                                   {log.food.name} 
                                   <span className="text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide">
                                     {log.food.servingSize || '1 serving'}
                                   </span>
                                 </div>
                                 <div className="text-xs text-slate-400 mt-1">
                                   P: {log.food.protein}g • C: {log.food.carbs}g • F: {log.food.fat}g
                                 </div>
                               </div>

                               <div className="flex items-center gap-3">
                                   <div className="font-bold text-slate-600">{log.food.calories}</div>

                                   {/* Menu Trigger */}
                                   <div className="relative">
                                       <button 
                                         onClick={(e) => { e.stopPropagation(); setMenuOpenId(menuOpenId === log.id ? null : log.id); }}
                                         className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-slate-200 text-slate-400 font-bold"
                                       >
                                         ⋯
                                       </button>

                                       {menuOpenId === log.id && (
                                            <div className="absolute right-0 top-full mt-1 bg-white border border-slate-200 shadow-xl rounded-xl z-10 w-32 overflow-hidden animate-fade-in-up origin-top-right">
                                                <button onClick={() => openEditModal(log)} className="w-full text-left px-4 py-2 text-sm text-slate-700 hover:bg-slate-50 font-medium">Edit</button>
