                        <button onClick={() => setEditScale(s => s + 0.25)} className="w-10 h-10 rounded-full bg-slate-100 font-bold hover:bg-slate-200">+</button>
                    </div>
                </div>
                <div className="flex gap-3">
                    <button onClick={() => setEditLog(null)} className="flex-1 py-3 font-bold text-slate-500 hover:bg-slate-50 rounded-xl">Cancel</button>
                    <button onClick={handleEditSave} className="flex-1 py-3 font-bold bg-brand-500 text-white rounded-xl hover:bg-brand-600 shadow-lg shadow-brand-500/30">Save</button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
