// utils/micronutrientScore.ts
import { MealLog, MicronutrientScoreBreakdown, MicronutrientScoreResult } from '../types';
import { NUTRIENT_INFO } from '../data/nutrientData';

export const PRIORITY_MICROS = [
  "Fiber", "Potassium", "Magnesium", "Iron", "Vitamin D", "Vitamin B12", "Calcium", "Vitamin C", "Zinc", "Folate"
];

const BADGE_TITLES: Record<string, string> = {
  "Fiber": "Fiber Hero",
  "Potassium": "Potassium Power",
  "Magnesium": "Magnesium Master",
  "Iron": "Iron Man/Woman",
  "Vitamin D": "Sunshine Soul",
  "Vitamin B12": "Energy Expert",
  "Calcium": "Bone Builder",
  "Vitamin C": "Immunity Idol",
  "Zinc": "Zinc Zenith",
  "Folate": "Folate Friend"
};

export const calculateMicronutrientScore = (logs: MealLog[]): MicronutrientScoreResult => {
  // 1. Aggregate consumed micros
  const consumed: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumed[name] = (consumed[name] || 0) + (amount as number);
      });
    }
  });

  let totalPoints = 0;
  const breakdown: MicronutrientScoreBreakdown[] = [];
  const newBadges: string[] = [];

  // 2. Score each priority micro
  // Scoring logic: 10 priority micros * 10 points max = 100 max score.
  PRIORITY_MICROS.forEach(micro => {
    const info = NUTRIENT_INFO[micro];
    if (!info || !info.targetVal) return;

    const current = consumed[micro] || 0;
    const target = info.targetVal;
    const pct = current / target;

    let points = 0;
    let status: 'low' | 'medium' | 'high' = 'low';

    if (pct >= 0.8) {
      points = 10;
      status = 'high';
      // Unlock badge candidate
      const badgeName = BADGE_TITLES[micro];
      if (badgeName) newBadges.push(badgeName);
    } else if (pct >= 0.5) {
      points = 5;
      status = 'medium';
    }

    totalPoints += points;
    breakdown.push({
      nutrient: micro,
      current,
      target,
      status,
      points
    });
  });

  // Clamp 0-100 (though math ensures it shouldn't exceed 100 if we have 10 items * 10pts)
  const score = Math.min(100, Math.max(0, totalPoints));

  return {
    score,
    breakdown,
    newBadges
  };
};
