        <div className="animate-fade-in space-y-8">

           {/* Micronutrient Score Card */}
           <div className="bg-gradient-to-br from-slate-900 to-slate-800 text-white p-8 rounded-3xl shadow-xl flex items-center justify-between">
              <div>
                 <h3 className="text-xl font-bold mb-1">Daily Nutrient Score</h3>
                 <p className="text-slate-400 text-sm">Based on 10 priority micronutrients</p>
              </div>
              <div className="relative w-24 h-24 flex items-center justify-center">
                 {/* Ring SVG */}
                 <svg className="w-full h-full transform -rotate-90">
                    <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-700" />
                    <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-brand-500 transition-all duration-1000 ease-out" strokeDasharray={251.2} strokeDashoffset={251.2 - (251.2 * microScore.score) / 100} />
                 </svg>
                 <span className="absolute text-2xl font-black">{microScore.score}</span>
              </div>
           </div>

           {/* Macros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
             <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
               📊 Macro Targets
             </h3>
             <ProgressBar 
               label="Protein" 
               current={consumedMacros.protein} 
               target={targets.protein} 
               unit="g"
               colorClass="bg-blue-500" 
             />
             <ProgressBar 
               label="Carbohydrates" 
               current={consumedMacros.carbs} 
               target={targets.carbs} 
               unit="g"
               colorClass="bg-amber-400" 
             />
             <ProgressBar 
               label="Fats" 
               current={consumedMacros.fat} 
               target={targets.fat} 
               unit="g"
               colorClass="bg-rose-400" 
             />
             <ProgressBar 
               label="Fiber" 
               current={consumedMicros["Fiber"] || 0} 
               target={NUTRIENT_INFO["Fiber"].targetVal || 30} 
               unit="g"
               colorClass="bg-emerald-500" 
             />
             <ProgressBar 
               label="Sugar" 
               current={consumedMicros["Sugar"] || 0} 
               target={NUTRIENT_INFO["Sugar"].targetVal || 50} 
               unit="g"
               colorClass="bg-purple-400" 
             />
           </section>

           {/* Micros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-2">Micronutrient Breakdown</h3>
              <p className="text-sm text-slate-500 mb-6">Tap any nutrient to learn more about why you need it.</p>

              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                 {/* Combine static list keys with consumed keys to ensure we show everything relevant.
                     We also explicitly filter out macros that are already shown above.
                  */}
                 {Array.from(new Set([...Object.keys(consumedMicros), ...Object.keys(NUTRIENT_INFO)])).filter(k => !['Protein','Carbohydrates','Fats','Fiber','Sugar'].includes(k)).map(key => {
                    const amount = consumedMicros[key] || 0;
                    const info = NUTRIENT_INFO[key];
                    const hasData = !!info;
                    const target = info?.targetVal;
                    const unit = info?.unit || '';

                    return (
                      <button 
                        key={key}
                        onClick={() => setSelectedNutrient(key)}
                        disabled={!hasData}
                        className={`p-4 rounded-xl border-2 text-left transition-all hover:scale-[1.02] active:scale-95 flex flex-col justify-between min-h-[100px]
                          ${hasData ? 'border-slate-100 hover:border-brand-300 bg-slate-50' : 'border-transparent opacity-50 cursor-default'}
                        `}
                      >
                         <div className="text-xs font-bold text-slate-400 uppercase mb-1 truncate w-full" title={key}>{key}</div>

                         <div>
                            <div className="text-lg font-black text-slate-800 flex items-baseline gap-0.5">
                              {amount > 0 ? Math.round(amount * 10) / 10 : '-'}
                              {unit && <span className="text-xs font-normal text-slate-500">{unit}</span>}
                            </div>

                            {target && amount > 0 && (
                                <div className={`text-xs font-bold mt-1 ${
                                    (amount / target) > 1.2 ? 'text-amber-500' : 
                                    (amount / target) > 0.8 ? 'text-green-500' : 'text-slate-400'
                                }`}>
                                    {Math.round((amount / target) * 100)}% DV
                                </div>
                            )}
                         </div>
                      </button>
                    )
                 })}
              </div>
           </section>

           <NutrientDetailModal />
        </div>
      )}

      {/* Edit Modal */}
      {editLog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
            <div className="bg-white rounded-2xl p-6 w-full max-w-sm animate-fade-in-up">
                <h3 className="text-lg font-bold text-slate-800 mb-4">Edit Entry</h3>
                <div className="mb-4">
                    <p className="text-sm font-medium text-slate-600 mb-1">{editLog.food.name}</p>
                    <div className="flex gap-2">
                        <input 
                          type="number" 
                          value={editQty} 
                          onChange={(e) => setEditQty(parseFloat(e.target.value))}
                          className="flex-1 p-3 border-2 border-slate-200 rounded-xl font-bold text-lg focus:border-brand-500 focus:outline-none"
                        />
                        <div className="flex items-center justify-center bg-slate-100 px-4 rounded-xl font-bold text-slate-500">
                            {editUnit}
                        </div>
                    </div>
                </div>

                {/* Quick Adjust Buttons */}
                <div className="flex gap-2 mb-6">
                    {['g', 'oz', 'ml'].some(u => editUnit.toLowerCase().includes(u)) ? (
                        <>
                             <button onClick={() => adjustEditQty(10)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-600 hover:bg-slate-200">+10</button>
                             <button onClick={() => adjustEditQty(25)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-600 hover:bg-slate-200">+25</button>
                             <button onClick={() => adjustEditQty(50)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-600 hover:bg-slate-200">+50</button>
                        </>
                    ) : (
                         <>
                             <button onClick={() => adjustEditQty(0.25)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-600 hover:bg-slate-200">+0.25</button>
                             <button onClick={() => adjustEditQty(0.5)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-600 hover:bg-slate-200">+0.5</button>
                             <button onClick={() => adjustEditQty(1)} className="px-3 py-2 bg-slate-100 rounded-lg text-sm font-bold text-slate-600 hover:bg-slate-200">+1</button>
                        </>
                    )}
                </div>

                <div className="flex gap-3">
                    <button onClick={() => setEditLog(null)} className="flex-1 py-3 font-bold text-slate-500 hover:bg-slate-50 rounded-xl">Cancel</button>
                    <button onClick={handleSaveEdit} className="flex-1 py-3 font-bold bg-brand-500 text-white rounded-xl hover:bg-brand-600 shadow-lg shadow-brand-500/30">Save Changes</button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
